package com.khamphaviet.restaurant.billing;
import jakarta.validation.Valid;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/v1/staff/checkouts") public class CheckoutController{private final CheckoutService service;private final PayPalSandboxService paypal;public CheckoutController(CheckoutService service,PayPalSandboxService paypal){this.service=service;this.paypal=paypal;}@GetMapping public List<CheckoutDtos.Checkout> list(){return service.list();}@PostMapping("/{sessionId}/pay")public CheckoutDtos.Checkout pay(@PathVariable Long sessionId,@Valid @RequestBody CheckoutDtos.PayRequest request){return service.pay(sessionId,request);}@GetMapping("/paypal/config")public CheckoutDtos.PayPalConfig paypalConfig(){return paypal.config();}@PostMapping("/{sessionId}/paypal/orders")public CheckoutDtos.PayPalOrder createPayPalOrder(@PathVariable Long sessionId,@Valid @RequestBody CheckoutDtos.PayPalRequest request){return paypal.createOrder(sessionId,request.discountAmount());}@PostMapping("/{sessionId}/paypal/orders/{orderId}/capture")public CheckoutDtos.Checkout capturePayPalOrder(@PathVariable Long sessionId,@PathVariable String orderId,@Valid @RequestBody CheckoutDtos.PayPalRequest request){return paypal.captureOrder(sessionId,orderId,request.discountAmount());}}
